import{_ as o,o as t,c as i,ag as a}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Testing Strategy","description":"","frontmatter":{},"headers":[],"relativePath":"sessions/2026-03-03-policy-wrapper-standardization/06_TESTING_STRATEGY.md","filePath":"sessions/2026-03-03-policy-wrapper-standardization/06_TESTING_STRATEGY.md"}'),c={name:"sessions/2026-03-03-policy-wrapper-standardization/06_TESTING_STRATEGY.md"};function l(s,e,n,r,d,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h1><h2 id="dispatch-host-hook-smoke-test-specification" tabindex="-1">Dispatch Host-Hook Smoke Test Specification <a class="header-anchor" href="#dispatch-host-hook-smoke-test-specification" aria-label="Permalink to &quot;Dispatch Host-Hook Smoke Test Specification&quot;">​</a></h2><h3 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h3><p>Create a minimal smoke test that proves host-side dispatch behavior for one conditionally allowed command and one conditionally blocked command.</p><h3 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h3><ul><li>Script: <code>wrappers/policy-wrapper-dispatch.sh</code></li><li>Inputs: <ul><li><code>policy-wrapper-rules.json</code></li><li><code>policy-wrapper-dispatch.manifest.json</code> from <code>sync_host_rules.py</code></li><li>Temporary clean and dirty git repositories for deterministic condition evaluation</li></ul></li></ul><h3 id="partial-comment-scan-behavior-note" tabindex="-1">Partial comment scan behavior note <a class="header-anchor" href="#partial-comment-scan-behavior-note" aria-label="Permalink to &quot;Partial comment scan behavior note&quot;">​</a></h3><ul><li>In this smoke/spec context, comment checks are expected to be tolerant of partial command failures when API endpoints return incomplete comment payloads.</li><li>The lane4 audit still treats any comment scan error as a hard block (<code>exit code 2</code>) in read-only mode so operators can triage before merge when policy context is uncertain.</li></ul><h3 id="positive-path" tabindex="-1">Positive path <a class="header-anchor" href="#positive-path" aria-label="Permalink to &quot;Positive path&quot;">​</a></h3><ol><li>Use a bundle with a single command rule. <ul><li><code>action: allow</code></li><li><code>conditions: { all: [&quot;git_clean_worktree&quot;] }</code></li><li><code>pattern</code>: command expected to be evaluated.</li></ul></li><li>Run dispatch with <code>--json</code> and the command string.</li><li>Assert: <ul><li><code>decision</code> is <code>allow</code></li><li><code>matched</code> is <code>true</code></li><li><code>condition_passed</code> is <code>true</code></li><li><code>rule_id</code> matches the allow rule id.</li></ul></li></ol><h3 id="blocked-path" tabindex="-1">Blocked path <a class="header-anchor" href="#blocked-path" aria-label="Permalink to &quot;Blocked path&quot;">​</a></h3><ol><li>Reuse a similar bundle shape with a single rule. <ul><li><code>action: allow</code></li><li><code>on_mismatch: deny</code></li><li><code>conditions: { all: [&quot;git_clean_worktree&quot;] }</code></li></ul></li><li>Execute with a dirty git worktree so condition evaluation succeeds but returns false.</li><li>Assert: <ul><li><code>decision</code> is <code>deny</code></li><li><code>matched</code> is <code>true</code></li><li><code>condition_passed</code> is <code>false</code></li><li>condition evaluation remains deterministic without relying on wrapper fallback defaults.</li></ul></li></ol><h3 id="success-criteria" tabindex="-1">Success criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success criteria&quot;">​</a></h3><ul><li>Smoke test covers both evaluation outcomes in one loop.</li><li>Script exit code follows current transport contract: <ul><li><code>0</code> =&gt; allow</li><li><code>1</code> =&gt; request</li><li><code>2</code> =&gt; deny</li></ul></li><li>Both outcomes preserve deterministic JSON schema emitted by <code>policy-wrapper-dispatch.sh</code>.</li></ul><h3 id="implementation-note" tabindex="-1">Implementation note <a class="header-anchor" href="#implementation-note" aria-label="Permalink to &quot;Implementation note&quot;">​</a></h3><ul><li>Keep this as a dedicated host-hook smoke test artifact under <code>docs/sessions/2026-03-03-policy-wrapper-standardization/</code>.</li><li>Prefer executing it as a script-adjacent local test (<code>bash</code> + <code>jq</code>) before any host rollout.</li></ul><h3 id="execution-status-resumed-lane-4-pass" tabindex="-1">Execution status (resumed lane-4 pass) <a class="header-anchor" href="#execution-status-resumed-lane-4-pass" aria-label="Permalink to &quot;Execution status (resumed lane-4 pass)&quot;">​</a></h3><ul><li>The smoke contract is now implemented in <code>scripts/smoke_dispatch_host_hook.sh</code>.</li><li>Tests in <code>tests/test_smoke_dispatch_host_hook.py</code> validate both allow and blocked dispatch paths using deterministic mocked wrapper output.</li><li>Workflow-stage audit integration now emits a lane4 <code>::error::</code> annotation for <code>comment_scan_errors</code>, and failure strings in <code>.github/workflows/policy-contract-governance.yml</code> now cross-link back to session docs.</li></ul>',18)])])}const m=o(c,[["render",l]]);export{u as __pageData,m as default};
